{
    "meta:resourceType": "schemas",
    "title": "Luma Test Profiles Schema",
    "type": "object",
    "description": "Schema for AJO test profiles for Luma Retail",
    "allOf": [
        {
            "$ref": "https://ns.adobe.com/xdm/context/profile",
            "type": "object",
            "meta:xdmType": "object"
        },
        {
            "$ref": "https://ns.adobe.com/xdm/context/profile-personal-details",
            "type": "object",
            "meta:xdmType": "object"
        },
        {
            "$ref": "https://ns.adobe.com/xdm/context/profile-person-details",
            "type": "object",
            "meta:xdmType": "object"
        },
        {
            "$ref": "https://ns.adobe.com/xdm/context/profile-test-profile",
            "type": "object",
            "meta:xdmType": "object"
        },
        {
            "$ref": "{{luma_identity_profile_fieldgroup_id}}",
            "type": "object",
            "meta:xdmType": "object"
        }
    ],
    "meta:extensible": false,
    "meta:abstract": false,
    "meta:extends": [
        "https://ns.adobe.com/xdm/context/profile-person-details",
        "https://ns.adobe.com/xdm/context/profile-personal-details",
        "https://ns.adobe.com/xdm/common/auditable",
        "https://ns.adobe.com/xdm/data/record",
        "https://ns.adobe.com/xdm/context/profile",
        "https://ns.adobe.com/xdm/context/profile-test-profile",
        "{{luma_identity_profile_fieldgroup_id}}"
    ],
    "meta:xdmType": "object",
    "meta:immutableTags": [
        "union"
    ]
}

{
    "name": "Luma Test Profiles Dataset",
    "schemaRef": {
        "id": "{{luma_test_profiles_schema_id}}",
        "contentType": "application/vnd.adobe.xed-full-notext+json; version=1"
    },
    "fileDescription": {
        "persisted": true,
        "containerFormat": "parquet",
        "format": "parquet"
    },
    "tags": {
        "unifiedProfile": ["enabled:true"],
        "unifiedIdentity": ["enabled:true"]
    },
    "enableErrorDiagnostics": true
}
